function connectWifi(){const e=document.getElementById("wifi_ssid").value.trim(),n=document.getElementById("wifi_password").value.trim();""!==e?(document.getElementById("loadingOverlay").style.display="block",document.getElementById("connectButton").disabled=!0,fetch("/api/wifi-connect",{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:"ssid="+encodeURIComponent(e)+"&password="+encodeURIComponent(n)}).then(e=>{if(!e.ok)throw new Error("Failed to connect to WiFi network");return e.json()}).then(e=>{document.getElementById("loadingOverlay").style.display="none",document.getElementById("connectButton").disabled=!1;const n=e.hostname;showMessage("Success!\n\n&#x26A0;&#xFE0F; Please turn your device upside down NOW &#x26A0;&#xFE0F;\n\n",!0,n)}).catch(e=>{document.getElementById("loadingOverlay").style.display="none",document.getElementById("connectButton").disabled=!1,showMessage(e.message,!1)})):showMessage("Please enter a WiFi SSID",!1)}